import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=16000,
    thinking={
        "type": "enabled",
        "budget_tokens": 10000  # máximo tokens para razonar
    },
    messages=[{
        "role": "user",
        "content": "¿Hay infinitos números primos de la forma 4n+3?"
    }]
)

for block in response.content:
    if block.type == "thinking":
        print(f"Razonamiento: {block.thinking}")
    elif block.type == "text":
        print(f"Respuesta: {block.text}")

