import anthropic

client = anthropic.Anthropic()

# 1. Subir el archivo una sola vez
with open("balance_anual.pdf", "rb") as f:
    archivo = client.beta.files.upload(
        file=("balance_anual.pdf", f, "application/pdf"),
        betas=["files-api-2025-04-14"],
    )

# 2. Reutilizarlo en múltiples requests, sin volver a codificarlo
for pregunta in ["Resume el documento", "¿Cuál es la conclusión?", "Lista los riesgos"]:
    response = client.beta.messages.create(
        model="claude-opus-4-8",
        max_tokens=1024,
        betas=["files-api-2025-04-14"],
        messages=[{
            "role": "user",
            "content": [
                {"type": "text", "text": pregunta},
                {
                    "type": "document",
                    "source": {"type": "file", "file_id": archivo.id}
                }
            ]
        }],
    )
    print(response.content[0].text)
